const mainPageText=document.querySelector(".main-page-text"),label=document.querySelector(".menu-btn"),links=document.querySelector(".page-links");console.log(label,mainPageText,links),label.addEventListener("click",(()=>{"none"===mainPageText.style.display&&"none"===links.style.display?(mainPageText.style.display="block",links.style.display="flex"):(mainPageText.style.display="none",links.style.display="none")}));